import React from 'react';

const Sidebar = ({ activeItem, onItemClick }) => {
  const menuItems = [
    { id: 'chatbot', icon: 'ð¤', label: 'Chatbot' },
    { id: 'summarizer', icon: 'ð', label: 'Text Summarizer' },
    { id: 'generator', icon: 'ð', label: 'Image Generator' }
  ];

  return (
    <aside className="w-64 bg-white shadow-lg h-full">
      <div className="p-4">
        <h2 className="text-xl font-bold text-gray-800 mb-6">AI Tools</h2>
        <nav className="space-y-2">
          {menuItems.map((item) => (
            <button
              key={item.id}
              onClick={() => onItemClick(item.id)}
              className={`w-full flex items-center space-x-3 px-4 py-3 rounded-lg transition-colors duration-200 ${
                activeItem === item.id
                  ? 'bg-blue-500 text-white'
                  : 'text-gray-700 hover:bg-gray-100'
              }`}
            >
              <span className="text-xl">{item.icon}</span>
              <span className="font-medium">{item.label}</span>
            </button>
          ))}
        </nav>
      </div>
    </aside>
  );
};

export default Sidebar;
